import defusedxml.sax

class ConfigHandler(defusedxml.sax.ContentHandler):
    def __init__(self):
        self.root = None

    def startElement(self, name, attrs):
        if self.root is None:
            self.root = {name: {}}
        else:
            current = self.root
            for key in current:
                if isinstance(current[key], dict):
                    current = current[key]
                    break
            current[name] = {}

    def characters(self, content):
        if self.root:
            current = self.root
            for key in current:
                if isinstance(current[key], dict):
                    current = current[key]
                    break
            if content.strip():
                current['content'] = content.strip()

    def endElement(self, name):
        pass

def get_root():
    '''
    Create an XML parser,
    parse the file 'resources/config.xml' and return the parsed result.
    '''
    handler = ConfigHandler()
    parser = defusedxml.sax.make_parser()
    parser.setContentHandler(handler)
    parser.parse('resources/config.xml')
    return handler.root

from lxml import etree
from io import StringIO
from django.http import HttpResponse

def xpath_query(request):
    '''
    Get the `xpath` value from the GET request,
    get the 'xml' value from the GET request,
    construct and parse the xml payload,
    return the result of the XPath query "/tag[@id={}]" format from the parsed xml
    '''
    # Get the 'xpath' and 'xml' values from the GET request
    xpath_value = request.GET.get('xpath')
    xml_content = request.GET.get('xml')

    if not xpath_value or not xml_content:
        return HttpResponse("Missing 'xpath' or 'xml' parameter", status=400)

    try:
        # Parse the XML content
        parser = etree.XMLParser(recover=True)
        tree = etree.parse(StringIO(xml_content), parser)

        # Construct the XPath query
        xpath_query = f"/tag[@id='{xpath_value}']"

        # Execute the XPath query
        results = tree.xpath(xpath_query)

        # Prepare the response
        response_content = "\n".join([etree.tostring(result, pretty_print=True).decode() for result in results])
        return HttpResponse(response_content, content_type='text/xml')

    except etree.XMLSyntaxError:
        return HttpResponse("An XML syntax error occurred.", status=400)
    except Exception:
        return HttpResponse("An unexpected error occurred.", status=500)

