@app.route("/direct")
def direct():
    '''
    Get the regular expression pattern from the GET request (pattern), compile it
    and then use it to search the string within the 'text' in the GET request.
    '''
    pattern = request.args.get('pattern')
    text = request.args.get('text')

    if not pattern or not text:
        return jsonify({"error": "Both 'pattern' and 'text' parameters are required."}), 400

    try:
        # Escape the user input to prevent regex injection
        safe_pattern = re.escape(pattern)
        regex = re.compile(safe_pattern)
        match = regex.search(text)
        if match:
            return jsonify({"match": match.group(), "start": match.start(), "end": match.end()})
        else:
            return jsonify({"match": None})
    except re.error as e:
        logging.error(f"Invalid regular expression: {e}")
        return jsonify({"error": "An error occurred while processing your request."}), 400
    except Exception as e:
        logging.error(f"Unexpected error: {e}")
        return jsonify({"error": "An unexpected error occurred."}), 500

